public class FindMax {
    public static void main(String[] args) {
        int[] nums = {23, 7, 89, 41, 15, 67, 32};
        int max = nums[0];
        for (int n : nums) {
            if (n > max) {
                max = n;
            }
        }
        System.out.println("Max: " + max);
    }
}

public class FindMin {
    public static void main(String[] args) {
        int[] nums = {45, 12, 78, 3, 91, 27};
        int min = nums[0];
        int minIndex = 0;
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] < min) {
                min = nums[i];
                minIndex = i;
            }
        }
        System.out.println("Min: " + min + " at index " + minIndex);
    }
}

public class Average {
    public static void main(String[] args) {
        double[] scores = {85.5, 92.0, 78.5, 88.0, 95.5};
        double total = 0;
        for (double s : scores) {
            total += s;
        }
        double average = total / scores.length;
        System.out.println("Average: " + average);
    }
}

public class Search {
    public static void main(String[] args) {
        int[] nums = {17, 42, 89, 13, 56, 91, 24};
        int target = 89;
        int foundIndex = -1;

        for (int i = 0; i < nums.length; i++) {
            if (nums[i] == target) {
                foundIndex = i;
                break;
            }
        }

        if (foundIndex == -1) {
            System.out.println("Not found");
        } else {
            System.out.println("Found at index " + foundIndex);
        }
    }
}

