public class CountEvens {
    public static void main(String[] args) {
        int[] nums = {12, 7, 18, 23, 30, 41, 64, 9, 15, 22};
        int count = 0;
        for (int n : nums) {
            if (n % 2 == 0) {
                count++;
            }
        }
        System.out.println("Even count: " + count);
    }
}

